  "vulnerable": true,
  "cwe": "CWE-22",
  "location": "validatePath check after snprintf allows '../' traversal",
  "explanation": "The prefix check does not normalize the path, so '../' sequences can escape the intended directory."
}

{
  "vulnerable": true,
  "cwe": "CWE-78",
  "location": "strncat and system call in main",
  "explanation": "User-controlled input is concatenated into a command string and executed with system(), allowing command injection."
}

{
  "vulnerable": true,
  "cwe": "CWE-22",
  "location": "validatePath always returns true, allowing path traversal via argv[1]",
  "explanation": "The program concatenates user input to a file path without proper validation, enabling directory traversal attacks"
}

{
  "vulnerable": true,
  "cwe": "CWE-78",
  "location": "snprintf(command, sizeof(command), \"ls -l | head -n %s\", userInput)",
  "explanation": "User-controlled input is inserted into a shell command without sanitization, enabling command injection."
}

